css:
.loader {
  position: relative;
  display: inline-block;
  width: 88px;
  height: 12px;
  overflow: hidden;
  border-radius: 999px;
  background: rgba(99, 102, 241, 0.16);
}
.loader::before {
  content: "";
  position: absolute;
  inset: 0 auto 0 0;
  width: 38%;
  border-radius: inherit;
  background: #6366f1;
  animation: slide 1s ease-in-out infinite;
}
@keyframes slide {
  0% { transform: translateX(-100%); }
  100% { transform: translateX(270%); }
}
